const express = require('express');
const morgan = require('morgan');
const winston = require('winston');
const app = express();
const port = 3000;

app.use(express.json());

// Create a winston logger
const logger = winston.createLogger({
    level: 'info',
    format: winston.format.combine(
        winston.format.timestamp(),
        winston.format.json()
    ),
    transports: [
        new winston.transports.File({ filename: 'audit.log' })
    ]
});

// Custom token for morgan to log user data
morgan.token('user', (req) => {
    const username = req.body.username ? sanitizeInput(req.body.username) : 'unknown';
    const ip = req.ip;
    const customHeader = req.headers['x-custom-header'] ? sanitizeInput(req.headers['x-custom-header']) : 'none';
    return `User: ${username}, IP: ${ip}, Custom Header: ${customHeader}`;
});

// Use morgan for logging
app.use(morgan(':user', {
    stream: {
        write: (message) => logger.info(message.trim())
    }
}));

// Sanitize input to prevent log injection
function sanitizeInput(input) {
    return input.replace(/[\n\r]+/g, ' ').replace(/"/g, '\\"');
}

// Sample route to accept user input
app.post('/log', (req, res) => {
    res.send('Data logged successfully');
});

app.listen(port, () => {
    console.log(`Server running at http://localhost:${port}`);
});